SELECT id, name, status,
  CASE WHEN actionPlansData IS NULL THEN 'sem_plano' ELSE CONCAT('tem_plano (', CHAR_LENGTH(actionPlansData), ' bytes)') END as plano_status
FROM projects WHERE id = 90004;

